import * as XLSX from 'xlsx';
import { applyAllFilters } from './filterService';
import { processDashboardData } from './dataProcessor';
import type { DataRow } from '../types';

let cachedOriginalData: any[] = [];
let columnHeaders: string[] = [];

// Truy xuất giá trị cực nhanh từ mảng thô dựa trên index cột
function getValueFromRow(rowArr: any[], colName: string): any {
  const idx = columnHeaders.indexOf(colName);
  return idx !== -1 ? rowArr[idx] : undefined;
}

/**
 * Hàm tạo chữ ký định danh cho một dòng dữ liệu để so sánh trùng
 */
function getRowSignature(row: any): string {
  // Loại bỏ các trường ID tự sinh hoặc biến đổi (như STT) nếu có
  const { STT_1, computedRevenue, computedRevenueQD, parsedDate, ...rest } = row;
  // Sắp xếp keys để đảm bảo chữ ký đồng nhất
  return JSON.stringify(rest, Object.keys(rest).sort());
}

self.onmessage = async (e) => {
  const { type, payload } = e.data;

  try {
    if (type === 'IMPORT_FILE') {
      const { file, enableDeduplication } = payload;
      const arrayBuffer = await file.arrayBuffer();
      const data = new Uint8Array(arrayBuffer);

      const workbook = XLSX.read(data, { 
        type: 'array', 
        cellDates: true, 
        dense: true
      });

      const sheet = workbook.Sheets[workbook.SheetNames[0]];
      const rawRows: any[][] = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: '' });

      if (rawRows.length === 0) throw new Error("File không có dữ liệu");

      columnHeaders = rawRows[0].map((h: any) => String(h).trim());
      const dataContent = rawRows.slice(1);

      // Lọc trùng và Mapping
      const rowSignatures = new Set();
      const mappedData: any[] = [];

      for (const row of dataContent) {
        const xuatValue = getValueFromRow(row, 'Trạng thái xuất') || '';
        const ngayTao = getValueFromRow(row, 'Ngày tạo');

        const mappedRow = {
          'Mã kho tạo': getValueFromRow(row, 'Mã kho tạo'),
          'Trạng thái xuất': xuatValue,
          'Người tạo': getValueFromRow(row, 'Người tạo'),
          'Trạng thái hồ sơ': getValueFromRow(row, 'Trạng thái hồ sơ'),
          'Ngành hàng': getValueFromRow(row, 'Ngành hàng'),
          'Nhóm hàng': getValueFromRow(row, 'Nhóm hàng'),
          'Số lượng': getValueFromRow(row, 'Số lượng'),
          'Giá bán_1': getValueFromRow(row, 'Giá bán_1'),
          'Hình thức xuất': getValueFromRow(row, 'Hình thức xuất'),
          'Tên sản phẩm': getValueFromRow(row, 'Tên sản phẩm'),
          normalizedKho: String(getValueFromRow(row, 'Mã kho tạo') || ''),
          normalizedXuat: String(xuatValue).toLowerCase().includes('đã') ? 'Đã' : 'Chưa',
          normalizedNguoiTao: String(getValueFromRow(row, 'Người tạo') || ''),
          normalizedTrangThai: String(getValueFromRow(row, 'Trạng thái hồ sơ') || ''),
          parsedDate: ngayTao instanceof Date ? ngayTao : new Date(ngayTao)
        };

        if (enableDeduplication) {
          const sig = getRowSignature(mappedRow);
          if (rowSignatures.has(sig)) continue;
          rowSignatures.add(sig);
        }

        mappedData.push(mappedRow);
      }

      cachedOriginalData = mappedData;
      const result = processDashboardData(cachedOriginalData);
      self.postMessage({ type: 'SUCCESS', payload: result });
    }

    if (type === 'APPLY_FILTER') {
      const filtered = applyAllFilters(cachedOriginalData, payload);
      const result = processDashboardData(filtered);
      self.postMessage({ type: 'FILTER_SUCCESS', payload: result });
    }
  } catch (error: any) {
    self.postMessage({ type: 'ERROR', message: error.message });
  }
};

