 * Tạo chữ ký dòng để so sánh trùng
 */
function getRowSignature(row: any): string {
  // Chỉ lấy một số trường chính để tạo key cho nhanh
  const { normalizedKho, normalizedNguoiTao, computedRevenue, parsedDate } = row;
  return `${normalizedKho}|${normalizedNguoiTao}|${computedRevenue}|${parsedDate?.getTime()}`;
}

self.onmessage = async (e) => {
  const { type, payload } = e.data;

  // Cấu trúc log để gửi về UI nếu có lỗi
  const debugLog: any = {
    step: 'start',
    totalRowsRaw: 0,
    headerRowIndex: -1,
    detectedHeaders: [],
    columnMapping: {},
    sampleRowsResult: [], // Lưu lý do 5 dòng đầu tiên bị fail
    error: null
  };

  try {
    if (type === 'IMPORT_FILE') {
      const { file, enableDeduplication } = payload;

      debugLog.step = 'reading_file';
      const arrayBuffer = await file.arrayBuffer();
      const data = new Uint8Array(arrayBuffer);

      const workbook = XLSX.read(data, { 
        type: 'array', 
        cellDates: true, 
        dense: true, 
        cellNF: false, 
        cellText: false 
      });

      const sheet = workbook.Sheets[workbook.SheetNames[0]];
      const rawRows: any[][] = XLSX.utils.sheet_to_json(sheet, { header: 1, defval: '' });

      debugLog.totalRowsRaw = rawRows.length;
      if (rawRows.length === 0) throw new Error("File rỗng (0 dòng).");

      // 1. Dò tìm dòng tiêu đề
      debugLog.step = 'detecting_header';
      let headerRowIndex = -1;
      let headers: string[] = [];

      // Các từ khóa bắt buộc phải xuất hiện trong header
      const requiredKeywords = ['mã đơn hàng', 'ngày tạo', 'trạng thái'];

      for (let i = 0; i < Math.min(rawRows.length, 100); i++) {
        const row = rawRows[i];
        if (!row || row.length === 0) continue;

        const rowString = row.map(c => String(c).toLowerCase()).join(' ');
        const matchCount = requiredKeywords.reduce((acc, k) => acc + (rowString.includes(k) ? 1 : 0), 0);

        // Nếu tìm thấy ít nhất 2 từ khóa quan trọng
        if (matchCount >= 2) {
          headerRowIndex = i;
          headers = row.map(c => String(c || '').trim());
          break;
        }
      }

      debugLog.headerRowIndex = headerRowIndex;
      debugLog.detectedHeaders = headers;

      if (headerRowIndex === -1) {
        throw new Error(`Không tìm thấy dòng tiêu đề chứa: ${requiredKeywords.join(', ')}. Vui lòng kiểm tra 100 dòng đầu.`);
      }

      columnHeaders = headers;

      // 2. Map cột
      const idx = {
        kho: getColIndex(headers, ['mã kho tạo', 'mã kho']),
        xuat: getColIndex(headers, ['trạng thái xuất']),
        nguoiTao: getColIndex(headers, ['người tạo', 'nhân viên tạo']),
        trangThai: getColIndex(headers, ['trạng thái hồ sơ', 'loại hồ sơ']),
        nganhHang: getColIndex(headers, ['ngành hàng']),
        nhomHang: getColIndex(headers, ['nhóm hàng']),
        soLuong: getColIndex(headers, ['số lượng']),
        giaBan: getColIndex(headers, ['giá bán_1', 'giá bán']),
        hinhThuc: getColIndex(headers, ['hình thức xuất']),
        tenSP: getColIndex(headers, ['tên sản phẩm']),
        ngayTao: getColIndex(headers, ['ngày tạo']),
        huy: getColIndex(headers, ['trạng thái hủy']),
        tra: getColIndex(headers, ['tình trạng nhập trả', 'nhập trả']),
        thuTien: getColIndex(headers, ['trạng thái thu tiền'])
      };

      debugLog.columnMapping = idx;

      // Kiểm tra cột quan trọng
      if (idx.ngayTao === -1) throw new Error("Không tìm thấy cột 'Ngày tạo'");

      // 3. Duyệt dữ liệu
      debugLog.step = 'processing_rows';
      const dataRows = rawRows.slice(headerRowIndex + 1);
      const rowSignatures = new Set();
      const mappedData: any[] = [];
      let validCount = 0;

      for (let i = 0; i < dataRows.length; i++) {
        const row = dataRows[i];
        if (!row || row.length === 0) continue;

        // Debug log cho 5 dòng đầu tiên bị lỗi
        const failureReason: string[] = [];

        // Kiểm tra điều kiện lọc
        const valHuy = idx.huy > -1 ? String(row[idx.huy] || '').toLowerCase() : '';
        const valTra = idx.tra > -1 ? String(row[idx.tra] || '').toLowerCase() : '';
        const valThu = idx.thuTien > -1 ? String(row[idx.thuTien] || '').toLowerCase() : '';

        // Logic check
        const isHuyValid = valHuy === '' || valHuy.includes('chưa hủy');
        const isTraValid = valTra === '' || valTra.includes('chưa trả');
        const isThuValid = valThu === '' || valThu.includes('đã thu') || valThu.includes('đã thanh toán');

        if (!isHuyValid) failureReason.push(`Hủy='${valHuy}'`);
        if (!isTraValid) failureReason.push(`Trả='${valTra}'`);
        if (!isThuValid) failureReason.push(`Thu='${valThu}'`);

        if (failureReason.length > 0) {
          if (debugLog.sampleRowsResult.length < 5) {
            debugLog.sampleRowsResult.push({ rowIndex: i + headerRowIndex + 1, reason: failureReason.join(', ') });
          }
          continue; 
        }

        // Xử lý ngày tháng
        const ngayTaoVal = row[idx.ngayTao];
        let parsedDate: Date | undefined;

        if (ngayTaoVal instanceof Date) {
          parsedDate = ngayTaoVal;
        } else if (typeof ngayTaoVal === 'number') {
          parsedDate = new Date(Math.round((ngayTaoVal - 25569) * 86400 * 1000));
        } else if (typeof ngayTaoVal === 'string') {
           const d = new Date(ngayTaoVal);
           if (!isNaN(d.getTime())) parsedDate = d;
        }

        if (!parsedDate) {
           if (debugLog.sampleRowsResult.length < 5) {
            debugLog.sampleRowsResult.push({ rowIndex: i + headerRowIndex + 1, reason: `Lỗi ngày tạo: ${ngayTaoVal}` });
           }
           continue;
        }

        // Map dữ liệu
        const xuatValue = idx.xuat > -1 ? String(row[idx.xuat] || '') : '';
        const mappedRow = {
          'Mã kho tạo': idx.kho > -1 ? row[idx.kho] : '',
          'Trạng thái xuất': xuatValue,
          'Người tạo': idx.nguoiTao > -1 ? row[idx.nguoiTao] : '',
          'Trạng thái hồ sơ': idx.trangThai > -1 ? row[idx.trangThai] : '',
          'Ngành hàng': idx.nganhHang > -1 ? row[idx.nganhHang] : '',
          'Nhóm hàng': idx.nhomHang > -1 ? row[idx.nhomHang] : '',
          'Số lượng': idx.soLuong > -1 ? row[idx.soLuong] : 0,
          'Giá bán_1': idx.giaBan > -1 ? row[idx.giaBan] : 0,
          'Hình thức xuất': idx.hinhThuc > -1 ? row[idx.hinhThuc] : '',
          'Tên sản phẩm': idx.tenSP > -1 ? row[idx.tenSP] : '',

          normalizedKho: String(idx.kho > -1 ? row[idx.kho] || '' : ''),
          normalizedXuat: xuatValue.toLowerCase().includes('đã') ? 'Đã' : 'Chưa',
          normalizedNguoiTao: String(idx.nguoiTao > -1 ? row[idx.nguoiTao] || '' : ''),
          normalizedTrangThai: String(idx.trangThai > -1 ? row[idx.trangThai] || '' : ''),
          parsedDate: parsedDate
        };

        if (enableDeduplication) {
          const sig = getRowSignature(mappedRow);
          if (rowSignatures.has(sig)) continue;
          rowSignatures.add(sig);
        }

        mappedData.push(mappedRow);
        validCount++;
      }

      if (validCount === 0) {
        // Gắn debug info vào message lỗi để hiển thị ở UI
        const debugStr = JSON.stringify(debugLog, null, 2);
        throw new Error(`DEBUG_INFO: ${debugStr}`);
      }

      cachedOriginalData = mappedData;
      const result = processDashboardData(cachedOriginalData);

      self.postMessage({ type: 'SUCCESS', payload: result });
    }

    if (type === 'APPLY_FILTER') {
      const filtered = applyAllFilters(cachedOriginalData, payload);
      const result = processDashboardData(filtered);
      self.postMessage({ type: 'FILTER_SUCCESS', payload: result });
    }
  } catch (error: any) {
    debugLog.error = error.message;
    // Nếu lỗi có chữ DEBUG_INFO thì giữ nguyên, nếu không thì đóng gói lại
    const msg = error.message.includes('DEBUG_INFO') 
      ? error.message 
      : `DEBUG_INFO: ${JSON.stringify(debugLog, null, 2)} \nOriginal Error: ${error.message}`;

    self.postMessage({ type: 'ERROR', message: msg });
  }
};

