function startTimer() {
  stopTimer();
  processingTime.set(0);
  const start = Date.now();
  timerInterval = setInterval(() => {
    processingTime.set(Date.now() - start);
  }, 100);
}

function stopTimer() {
  if (timerInterval) {
    clearInterval(timerInterval);
    timerInterval = null;
  }
}

export function showToast(message: string, type: 'success' | 'error' | 'info' = 'info') {
  // Nếu thông báo quá dài (chứa debug info), cắt ngắn để hiển thị trên UI
  const displayMsg = message.includes('DEBUG_INFO') 
    ? "Lỗi xử lý file. Vui lòng mở Console (F12) để xem chi tiết và gửi cho admin." 
    : message;

  toastMessage.set({ message: displayMsg, type });
  setTimeout(() => toastMessage.set(null), 5000); // Tăng thời gian hiện lỗi
}

let worker: Worker | null = null;

export function getWorker() {
  if (!worker) {
    worker = new Worker(new URL('../services/worker.ts', import.meta.url), { type: 'module' });
    worker.onmessage = async (e) => {
      const { type, payload, message } = e.data;

      if (type === 'SUCCESS') {
        processedData.set(payload);
        appState.set('dashboard');

        requestAnimationFrame(() => {
          requestAnimationFrame(() => {
            setTimeout(() => {
              isProcessing.set(false);
              stopTimer();
            }, 500);
          });
        });

      } else if (type === 'FILTER_SUCCESS') {
        processedData.set(payload);
        isProcessing.set(false);
      } else if (type === 'ERROR') {

        // --- XỬ LÝ DEBUG ERROR ---
        if (message.includes('DEBUG_INFO')) {
            console.group("🛑 CHI TIẾT LỖI XỬ LÝ FILE");
            console.error("Vui lòng chụp ảnh hoặc copy toàn bộ nội dung bên dưới gửi cho kỹ thuật:");
            try {
                // Tách phần JSON ra khỏi chuỗi
                const jsonStr = message.replace('DEBUG_INFO: ', '').split('\nOriginal Error:')[0];
                const debugObj = JSON.parse(jsonStr);
                console.dir(debugObj);
            } catch (err) {
                console.error(message);
            }
            console.groupEnd();
        } else {
            console.error(message);
        }
        // -------------------------

        showToast(message, 'error');
        isProcessing.set(false);
        appState.set('upload');
        stopTimer();
      }
    };
  }
  return worker;
}

