      }

      columnHeaders = headers;

      // 2. Map cột (Sử dụng hàm getColIndex thông minh hơn)
      const idx = {
        maDonHang: getColIndex(headers, ['ma don hang', 'don hang']),
        kho: getColIndex(headers, ['ma kho tao', 'ma kho']),
        xuat: getColIndex(headers, ['trang thai xuat']),
        nguoiTao: getColIndex(headers, ['nguoi tao', 'nhan vien tao']),
        trangThai: getColIndex(headers, ['trang thai ho so', 'loai ho so']),
        nganhHang: getColIndex(headers, ['nganh hang']),
        nhomHang: getColIndex(headers, ['nhom hang']),
        soLuong: getColIndex(headers, ['so luong']),
        giaBan: getColIndex(headers, ['gia ban_1', 'gia ban']),
        hinhThuc: getColIndex(headers, ['hinh thuc xuat']),
        tenSP: getColIndex(headers, ['ten san pham']),
        ngayTao: getColIndex(headers, ['ngay tao']),
        // Các cột điều kiện lọc
        huy: getColIndex(headers, ['trang thai huy']),
        tra: getColIndex(headers, ['tinh trang nhap tra', 'nhap tra']),
